const data = $json.body.data.properties;

 // 📌 공통 파라미터
 const commonParams = {
   url_day: $json.body.data.id,
   학생이름: data["학생이름(S)"].formula.string,
   수업날짜: data["수업일시(S)"].formula.string,
   요일: data["요일"].formula.string,
   수업회차: data["수업회차(S)"].formula.string,
   과정: data["과정(S)"].formula.string,
   수업내용: data["진도/수업 내용"]?.rollup?.array[0]?.rich_text[0]?.plain_text || ""
 };

 // 📌 수신자 배열
 const list = [];

 // 연락처1 (필수)
 if (data["학부모연락처 1(S)"].formula.string) {
   list.push({
     recipientNo: data["학부모연락처 1(S)"].formula.string,
     templateParameter: commonParams
   });
 }

 // 연락처2 (있으면 추가)
 if (data["학부모연락처 2(S)"].formula.string) {
   list.push({
     recipientNo: data["학부모연락처 2(S)"].formula.string,
     templateParameter: commonParams
   });
 }

 // 📌 숫자만 추출하는 함수
 function extractNumber(str) {
   const match = (str || "").match(/\d+/);
   return match ? parseInt(match[0], 10) : null;
 }

 // 수업회차(S) 숫자
 const numFromSession = extractNumber(data["수업회차(S)"].formula.string);
 // 과정(S) 숫자
 const numFromCourse = extractNumber(data["과정(S)"].formula.string);

 // 비교 결과
 let sendPaymentNotice = false;
 if (numFromSession !== null && numFromCourse !== null && numFromSession === numFromCourse)
 {
   sendPaymentNotice = true;
 }

 // 최종 결과 리턴
 return [{
   json: {
     recipientList: list,
     sendPaymentNotice
   }
 }];
